mapper.update:
UPDATE tb_salary SET
    addition_amount  = #{additionAmount},
    deduction_amount = #{deductionAmount},
    payable_amount   = #{payableAmount}
WHERE id = #{id}

mapper.delete:
DELETE FROM tb_salary
WHERE project_id = #{projectId}
  AND salary_period = #{salaryPeriod}

mapper.select:
SELECT s.id, s.employee_id, s.salary_period, s.salary_type, s.base_salary, s.attendance_days, s.base_amount, s.addition_amount, s.deduction_amount, s.payable_amount, s.remark, s.approve_remark, s.project_id, s.created_time, s.updated_time, e.name AS employee_name, e.id_card AS id_card, e.phone AS phone, jc.name AS job_category_name FROM tb_salary s LEFT JOIN tb_employee e ON s.employee_id = e.id LEFT JOIN tb_job_category jc ON e.job_category_id = jc.id WHERE 1=1
AND s.employee_id = #{employeeId}
AND s.salary_period = #{salaryPeriod}
AND s.project_id = #{projectId}
ORDER BY s.salary_period DESC, e.name ASC

SELECT s.*, e.name AS employee_name
FROM tb_salary s
LEFT JOIN tb_employee e ON s.employee_id = e.id
WHERE s.employee_id = #{employeeId}
  AND s.salary_period = #{salaryPeriod}
  AND s.project_id = #{projectId}
